/**
 * @param {string} lStr
 * @param {string} rStr
 * @param {string} directions
 * @return {number}
 */
function solve(lStr, rStr, directions) {
    const l = BigInt(lStr);
    const r = BigInt(rStr);

    let goodCount = 0;

    for (let xBig = l; xBig <= r; xBig++) {
        // 1. Format x as a 16-digit string with leading zeros
        let xStr = xBig.toString().padStart(16, '0');

        // 2. Place digits into a 4x4 grid (row-major)
        const grid = Array(4).fill(0).map(() => Array(4).fill(0));
        let digitIndex = 0;
        for (let r = 0; r < 4; r++) {
            for (let c = 0; c < 4; c++) {
                if (digitIndex < 16) {
                    grid[r][c] = parseInt(xStr[digitIndex]);
                    digitIndex++;
                }
            }
        }

        // 3. Apply directions to trace the path
        let currentRow = 0;
        let currentCol = 0;
        const pathValues = [grid[currentRow][currentCol]]; // Start at (0, 0)

        // The path length is 7, meaning 1 starting point + 6 moves
        for (let i = 0; i < 6; i++) {
            const move = directions[i];

            if (move === 'D') {
                currentRow += 1;
            } else if (move === 'R') {
                currentCol += 1;
            }

            // Safety check (although problem constraints imply it won't go out of bounds for the 6 moves)
            if (currentRow >= 4 || currentCol >= 4) {
                // This case should not happen based on problem constraints (3D, 3R)
                break;
            }

            pathValues.push(grid[currentRow][currentCol]);
        }

        // 4. Check if the sequence is non-decreasing
        let isNonDecreasing = true;
        for (let i = 0; i < pathValues.length - 1; i++) {
            if (pathValues[i] > pathValues[i + 1]) {
                isNonDecreasing = false;
                break;
            }
        }

        if (isNonDecreasing) {
            goodCount++;
        }
    }

    return goodCount;
}

